import logo from "./logo.svg";
import "./App.css";
import Typewriter from "typewriter-effect";

function App() {
  return (
    <div className="App">
      <header className="App-header">
        <Profile />
        <Typewriter
          className={typewriter}
          onInit={(typewriter) => {
            typewriter
              .typeString("Hello World!")
              .callFunction(() => {
                console.log("String typed out!");
              })
              .pauseFor(2500)
              .deleteAll()
              .callFunction(() => {
                console.log("All strings were deleted");
              })
              .start();
          }}
        />
        <Navbar />
      </header>
    </div>
  );
}

export default App;
const Profile = () => {
  return (
    <>
      <div>
        <img src="#" alt="burgeon" className="display-pic" />
        <h1>
          Hello <span>Am Burgeon</span>
        </h1>
        {}
      </div>
    </>
  );
};
const Navbar = () => {};
